export const Calendar = (props: CalendarProps) => {
  const {
    className,
    defaultValue,
    value,
    isDateUnavailable,
    min,
    max,
    ...rest
  } = props;

  const normalizedDefaultValue = normalizeDateValue(defaultValue);
  const normalizedValue = normalizeDateValue(value);
  const normalizedMin = min instanceof Date ? toDateValue(min) : min;
  const normalizedMax = max instanceof Date ? toDateValue(max) : max;

  return (
    <ArkCalendar.Root
      className={cn("[--cell-size:--spacing(8)]", "w-fit", className)}
      data-slot="calendar"
      defaultValue={normalizedDefaultValue}
      inline
      isDateUnavailable={isDateUnavailable}
      max={normalizedMax}
      min={normalizedMin}
      value={normalizedValue}
      {...rest}
    />
  );
};

