interface DateLike {
  day: number;
  month: number;
  year: number;
}

function toDateValue(d: Date): CalendarDate {
  const year = getFullYear(d);
  const month = getMonth(d) + 1;
  const day = getDate(d);
  const valid =
    Number.isFinite(year) && Number.isFinite(month) && Number.isFinite(day);
  if (!valid) {
    const fallback = new Date();
    return new CalendarDate(
      getFullYear(fallback),
      getMonth(fallback) + 1,
      getDate(fallback)
    );
  }
  return new CalendarDate(year, month, day);
}

type ArkDateValue = React.ComponentProps<
  typeof ArkCalendar.Root
>["defaultValue"];

function isCalendarDate(d: unknown): d is CalendarDate {
  return (
    typeof d === "object" &&
    d !== null &&
    "calendar" in d &&
    typeof (d as CalendarDate).calendar?.getDaysInMonth === "function"
  );
}

function normalizeDateValue(v: Date | Date[] | ArkDateValue): ArkDateValue {
  if (v === undefined) {
    return undefined;
  }
  // Ark/zag-js always expects DateValue[] (even for single selection - array with one element)
  const arr = Array.isArray(v) ? v : [v];
  return arr.map((d) => {
    if (d instanceof Date) {
      return toDateValue(d);
    }
    if (
      !isCalendarDate(d) &&
      d &&
      typeof d === "object" &&
      "year" in d &&
      "month" in d &&
      "day" in d
    ) {
      const obj = d as { year: number; month: number; day: number };
      return new CalendarDate(obj.year, obj.month, obj.day);
    }
    return d;
  }) as unknown as ArkDateValue;
}

export interface CalendarProps
  extends Omit<
    React.ComponentProps<typeof ArkCalendar.Root>,
    "defaultValue" | "value"
  > {
  defaultValue?:
    | Date
    | Date[]
    | React.ComponentProps<typeof ArkCalendar.Root>["defaultValue"];
  /** Maximum number of dates that can be selected (multiple mode only). */
  maxSelectedDates?: number;
  value?:
    | Date
    | Date[]
    | React.ComponentProps<typeof ArkCalendar.Root>["value"];
}

/** Check if a calendar date (year, month, day) matches a native Date. Use in isDateUnavailable. */
export function isDateEqual(date: DateLike, d: Date): boolean {
  return (
    date.year === d.getFullYear() &&
    date.month === d.getMonth() + 1 &&
    date.day === d.getDate()
  );
}
